import Database from "better-sqlite3";
import { existsSync, mkdirSync } from "node:fs";
import { dirname, join } from "node:path";

// This module touches the filesystem and native bindings (better-sqlite3) and
// must only ever be imported from server-only code paths, i.e. from within
// routeLoader$ / routeAction$ callbacks. Qwik's optimizer extracts those
// callbacks into server-only QRL segments, so this module never ends up in
// the client bundle.

export interface TodoRow {
  id: string;
  title: string;
  completed: number;
}

export interface Todo {
  id: string;
  title: string;
  completed: boolean;
}

const DB_PATH = join(process.cwd(), "data", "todos.sqlite");

let db: Database.Database | undefined;

function getDb(): Database.Database {
  if (!db) {
    const dir = dirname(DB_PATH);
    if (!existsSync(dir)) {
      mkdirSync(dir, { recursive: true });
    }
    db = new Database(DB_PATH);
    db.pragma("journal_mode = WAL");
    db.exec(`
      CREATE TABLE IF NOT EXISTS todos (
        id TEXT PRIMARY KEY,
        title TEXT NOT NULL,
        completed INTEGER NOT NULL DEFAULT 0
      )
    `);
  }
  return db;
}

function rowToTodo(row: TodoRow): Todo {
  return {
    id: row.id,
    title: row.title,
    completed: !!row.completed,
  };
}

export function listTodos(): Todo[] {
  const rows = getDb()
    .prepare("SELECT id, title, completed FROM todos ORDER BY rowid ASC")
    .all() as TodoRow[];
  return rows.map(rowToTodo);
}

export function insertTodo(id: string, title: string): Todo {
  getDb()
    .prepare(
      "INSERT INTO todos (id, title, completed) VALUES (?, ?, 0)",
    )
    .run(id, title);
  return { id, title, completed: false };
}

export function setTodoCompleted(id: string, completed: boolean): Todo | undefined {
  getDb()
    .prepare("UPDATE todos SET completed = ? WHERE id = ?")
    .run(completed ? 1 : 0, id);
  const row = getDb()
    .prepare("SELECT id, title, completed FROM todos WHERE id = ?")
    .get(id) as TodoRow | undefined;
  return row ? rowToTodo(row) : undefined;
}

export function deleteTodo(id: string): void {
  getDb().prepare("DELETE FROM todos WHERE id = ?").run(id);
}

/** Simulated network/behavior helpers shared by all mutating actions. */
export function shouldSimulateFailure(title: string): boolean {
  return title.startsWith("FAIL");
}

export function shouldSimulateSlow(title: string): boolean {
  return title.startsWith("SLOW");
}

export async function simulateLatency(title: string): Promise<void> {
  if (shouldSimulateSlow(title)) {
    await new Promise((resolve) => setTimeout(resolve, 1100));
  }
}

import { $, component$, useStore, useVisibleTask$ } from "@builder.io/qwik";
import {
  routeAction$,
  routeLoader$,
  z,
  zod$,
  type DocumentHead,
} from "@builder.io/qwik-city";

export const useTodosLoader = routeLoader$(async () => {
  const { listTodos } = await import("~/lib/db");
  return listTodos();
});

export const useAddTodoAction = routeAction$(
  async (data, requestEvent) => {
    const { insertTodo, shouldSimulateFailure, simulateLatency } =
      await import("~/lib/db");

    if (shouldSimulateFailure(data.title)) {
      return requestEvent.fail(400, {
        message: `Failed to save "${data.title}": titles starting with "FAIL" are rejected by the server.`,
      });
    }

    await simulateLatency(data.title);

    const todo = insertTodo(data.id, data.title);
    return { success: true as const, todo };
  },
  zod$({
    id: z.string().min(1),
    title: z.string().min(1),
  }),
);

export const useToggleTodoAction = routeAction$(
  async (data, requestEvent) => {
    const { setTodoCompleted, shouldSimulateFailure, simulateLatency } =
      await import("~/lib/db");

    if (shouldSimulateFailure(data.title)) {
      return requestEvent.fail(400, {
        message: `Failed to update "${data.title}": titles starting with "FAIL" are rejected by the server.`,
      });
    }

    await simulateLatency(data.title);

    const todo = setTodoCompleted(data.id, data.completed);
    if (!todo) {
      return requestEvent.fail(404, {
        message: `Todo "${data.title}" was not found.`,
      });
    }
    return { success: true as const, todo };
  },
  zod$({
    id: z.string().min(1),
    title: z.string().min(1),
    completed: z.boolean(),
  }),
);

export const useDeleteTodoAction = routeAction$(
  async (data, requestEvent) => {
    const { deleteTodo, shouldSimulateFailure, simulateLatency } =
      await import("~/lib/db");

    if (shouldSimulateFailure(data.title)) {
      return requestEvent.fail(400, {
        message: `Failed to delete "${data.title}": titles starting with "FAIL" are rejected by the server.`,
      });
    }

    await simulateLatency(data.title);

    deleteTodo(data.id);
    return { success: true as const, id: data.id };
  },
  zod$({
    id: z.string().min(1),
    title: z.string().min(1),
  }),
);

interface OptimisticTodo {
  id: string;
  title: string;
  completed: boolean;
}

function createId(): string {
  if (typeof crypto !== "undefined" && "randomUUID" in crypto) {
    return crypto.randomUUID();
  }
  return `tmp-${Date.now()}-${Math.random().toString(36).slice(2)}`;
}

export default component$(() => {
  const todosLoader = useTodosLoader();
  const addTodoAction = useAddTodoAction();
  const toggleTodoAction = useToggleTodoAction();
  const deleteTodoAction = useDeleteTodoAction();

  const store = useStore<{
    todos: OptimisticTodo[];
    pending: Record<string, boolean>;
    error: string | null;
    newTitle: string;
  }>({
    todos: todosLoader.value.map((t) => ({ ...t })),
    pending: {},
    error: null,
    newTitle: "",
  });

  const addTodo = $(async () => {
    const title = store.newTitle.trim();
    if (!title) return;

    const id = createId();
    store.error = null;
    store.newTitle = "";

    // Optimistic insert.
    store.todos.push({ id, title, completed: false });
    store.pending[id] = true;

    const result = await addTodoAction.submit({ id, title });

    store.pending[id] = false;

    if (result.value.failed) {
      // Roll back the optimistic insert.
      store.todos = store.todos.filter((t) => t.id !== id);
      store.error =
        (result.value as { message?: string }).message ??
        "Failed to add todo.";
      return;
    }

    // Reconcile with server truth.
    const persisted = (
      result.value as {
        success: true;
        todo: { id: string; title: string; completed: boolean };
      }
    ).todo;
    const idx = store.todos.findIndex((t) => t.id === id);
    if (idx !== -1) {
      store.todos[idx] = { ...persisted };
    }
  });

  const toggleTodo = $(async (id: string) => {
    const todo = store.todos.find((t) => t.id === id);
    if (!todo) return;

    const previousCompleted = todo.completed;
    const nextCompleted = !previousCompleted;

    store.error = null;
    // Optimistic update.
    todo.completed = nextCompleted;
    store.pending[id] = true;

    const result = await toggleTodoAction.submit({
      id,
      title: todo.title,
      completed: nextCompleted,
    });

    store.pending[id] = false;

    if (result.value.failed) {
      // Roll back.
      const rollbackTodo = store.todos.find((t) => t.id === id);
      if (rollbackTodo) {
        rollbackTodo.completed = previousCompleted;
      }
      store.error =
        (result.value as { message?: string }).message ??
        "Failed to update todo.";
      return;
    }

    const persisted = (
      result.value as {
        success: true;
        todo: { id: string; title: string; completed: boolean };
      }
    ).todo;
    const idx = store.todos.findIndex((t) => t.id === id);
    if (idx !== -1) {
      store.todos[idx] = { ...persisted };
    }
  });

  const deleteTodoHandler = $(async (id: string) => {
    const todo = store.todos.find((t) => t.id === id);
    if (!todo) return;

    const index = store.todos.findIndex((t) => t.id === id);
    const removed = { ...todo };

    store.error = null;
    // Optimistic removal.
    store.todos = store.todos.filter((t) => t.id !== id);
    store.pending[id] = true;

    const result = await deleteTodoAction.submit({ id, title: removed.title });

    store.pending[id] = false;

    if (result.value.failed) {
      // Roll back: re-insert at original position.
      const restored = [...store.todos];
      restored.splice(index, 0, removed);
      store.todos = restored;
      store.error =
        (result.value as { message?: string }).message ??
        "Failed to delete todo.";
    }
  });

  // Keep server-provided pending flag purely client-driven; nothing to sync
  // from a visible task, but this hook is a natural extension point if the
  // loader data ever needs revalidation.
  // eslint-disable-next-line qwik/no-use-visible-task
  useVisibleTask$(() => {
    // no-op: initial data already hydrated from the loader into the store.
  });

  return (
    <>
      <h1>Todos</h1>

      <div>
        <input
          data-testid="new-todo-input"
          type="text"
          value={store.newTitle}
          placeholder="What needs to be done?"
          onInput$={(_, el) => {
            store.newTitle = el.value;
          }}
          onKeyDown$={(ev) => {
            if (ev.key === "Enter") {
              addTodo();
            }
          }}
        />
        <button data-testid="add-todo" type="button" onClick$={addTodo}>
          Add
        </button>
      </div>

      {store.error && (
        <div data-testid="error-message" role="alert">
          {store.error}
        </div>
      )}

      <ul data-testid="todo-list">
        {store.todos.map((todo) => (
          <li
            key={todo.id}
            data-testid="todo-item"
            data-title={todo.title}
            data-pending={store.pending[todo.id] ? "true" : "false"}
          >
            <input
              type="checkbox"
              checked={todo.completed}
              onChange$={() => toggleTodo(todo.id)}
            />
            <span
              style={{
                textDecoration: todo.completed ? "line-through" : "none",
              }}
            >
              {todo.title}
            </span>
            <button
              data-testid="delete-todo"
              type="button"
              onClick$={() => deleteTodoHandler(todo.id)}
            >
              Delete
            </button>
          </li>
        ))}
      </ul>
    </>
  );
});

export const head: DocumentHead = {
  title: "Optimistic Todos",
  meta: [
    {
      name: "description",
      content: "Optimistic-UI todo app with server reconciliation",
    },
  ],
};

